const express = require('express');
const session = require('express-session');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');

const app = express();

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.use(session({
  secret: crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 15 * 60 * 1000,
    sameSite: 'strict'
  }
}));

const mfaStore = new Map();

const MAX_ATTEMPTS = 3;
const CODE_EXPIRY = 5 * 60 * 1000;
const RATE_LIMIT_WINDOW = 15 * 60 * 1000;
const MAX_REQUESTS_PER_WINDOW = 5;

const sendSMSLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  max: MAX_REQUESTS_PER_WINDOW,
  message: 'Too many SMS requests, please try again later',
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => {
    return req.session.userId || req.ip;
  }
});

const verifyLimiter = rateLimit({
  windowMs: RATE_LIMIT_WINDOW,
  max: MAX_ATTEMPTS * 2,
  message: 'Too many verification attempts, please try again later',
  standardHeaders: true,
  legacyHeaders: false,
  keyGenerator: (req) => {
    return req.session.userId || req.ip;
  }
});

function generateSecureCode() {
  const code = crypto.randomInt(100000, 999999).toString();
  return code;
}

function hashCode(code, salt) {
  return crypto.pbkdf2Sync(code, salt, 10000, 64, 'sha512').toString('hex');
}

async function sendSMS(phoneNumber, code) {
  const accountSid = process.env.TWILIO_ACCOUNT_SID;
  const authToken = process.env.TWILIO_AUTH_TOKEN;
  const fromNumber = process.env.TWILIO_PHONE_NUMBER;

  if (!accountSid || !authToken || !fromNumber) {
    throw new Error('Twilio credentials not configured');
  }

  const twilio = require('twilio');
  const client = twilio(accountSid, authToken);

  try {
    await client.messages.create({
      body: `Your verification code is: ${code}. This code will expire in 5 minutes. Do not share this code with anyone.`,
      from: fromNumber,
      to: phoneNumber
    });
    return true;
  } catch (error) {
    console.error('SMS sending failed:', error);
    throw new Error('Failed to send SMS');
  }
}

function validatePhoneNumber(phoneNumber) {
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return phoneRegex.test(phoneNumber);
}

function cleanupExpiredCodes() {
  const now = Date.now();
  for (const [key, data] of mfaStore.entries()) {
    if (now > data.expiresAt) {
      mfaStore.delete(key);
    }
  }
}

setInterval(cleanupExpiredCodes, 60000);

app.post('/api/auth/send-mfa-code', sendSMSLimiter, async (req, res) => {
  try {
    const { phoneNumber, userId } = req.body;

    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'User ID and phone number are required' });
    }

    if (!validatePhoneNumber(phoneNumber)) {
      return res.status(400).json({ error: 'Invalid phone number format. Use E.164 format (e.g., +1234567890)' });
    }

    req.session.userId = userId;
    req.session.phoneNumber = phoneNumber;

    const code = generateSecureCode();
    const salt = crypto.randomBytes(16).toString('hex');
    const hashedCode = hashCode(code, salt);

    const mfaData = {
      hashedCode,
      salt,
      attempts: 0,
      createdAt: Date.now(),
      expiresAt: Date.now() + CODE_EXPIRY,
      phoneNumber
    };

    mfaStore.set(userId, mfaData);

    await sendSMS(phoneNumber, code);

    res.json({
      success: true,
      message: 'Verification code sent successfully',
      expiresIn: CODE_EXPIRY / 1000
    });

  } catch (error) {
    console.error('Error sending MFA code:', error);
    res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/api/auth/verify-mfa-code', verifyLimiter, (req, res) => {
  try {
    const { code } = req.body;
    const userId = req.session.userId;

    if (!userId) {
      return res.status(401).json({ error: 'No active session' });
    }

    if (!code || !/^\d{6}$/.test(code)) {
      return res.status(400).json({ error: 'Invalid code format' });
    }

    const mfaData = mfaStore.get(userId);

    if (!mfaData) {
      return res.status(400).json({ error: 'No verification code found. Please request a new code.' });
    }

    if (Date.now() > mfaData.expiresAt) {
      mfaStore.delete(userId);
      return res.status(400).json({ error: 'Verification code has expired. Please request a new code.' });
    }

    if (mfaData.attempts >= MAX_ATTEMPTS) {
      mfaStore.delete(userId);
      return res.status(429).json({ error: 'Maximum verification attempts exceeded. Please request a new code.' });
    }

    mfaData.attempts++;

    const hashedInputCode = hashCode(code, mfaData.salt);

    if (crypto.timingSafeEqual(Buffer.from(hashedInputCode), Buffer.from(mfaData.hashedCode))) {
      mfaStore.delete(userId);
      req.session.mfaVerified = true;
      req.session.mfaVerifiedAt = Date.now();

      return res.json({
        success: true,
        message: 'Verification successful'
      });
    } else {
      const remainingAttempts = MAX_ATTEMPTS - mfaData.attempts;

      if (remainingAttempts === 0) {
        mfaStore.delete(userId);
        return res.status(400).json({
          error: 'Invalid verification code. Maximum attempts exceeded. Please request a new code.',
          remainingAttempts: 0
        });
      }

      return res.status(400).json({
        error: 'Invalid verification code',
        remainingAttempts
      });
    }

  } catch (error) {
    console.error('Error verifying MFA code:', error);
    res.status(500).json({ error: 'Verification failed' });
  }
});

app.get('/api/auth/mfa-status', (req, res) => {
  const userId = req.session.userId;

  if (!userId) {
    return res.status(401).json({ error: 'No active session' });
  }

  const mfaData = mfaStore.get(userId);
  const isVerified = req.session.mfaVerified === true;

  res.json({
    hasPendingCode: !!mfaData,
    isVerified,
    expiresAt: mfaData ? mfaData.expiresAt : null,
    remainingAttempts: mfaData ? MAX_ATTEMPTS - mfaData.attempts : 0
  });
});

app.post('/api/auth/logout', (req, res) => {
  const userId = req.session.userId;
  
  if (userId) {
    mfaStore.delete(userId);
  }

  req.session.destroy((err) => {
    if (err) {
      return res.status(500).json({ error: 'Logout failed' });
    }
    res.json({ success: true, message: 'Logged out successfully' });
  });
});

function requireMFA(req, res, next) {
  if (!req.session.mfaVerified) {
    return res.status(403).json({ error: 'MFA verification required' });
  }

  const mfaAge = Date.now() - (req.session.mfaVerifiedAt || 0);
  const MFA_VALIDITY = 30 * 60 * 1000;

  if (mfaAge > MFA_VALIDITY) {
    req.session.mfaVerified = false;
    return res.status(403).json({ error: 'MFA verification expired. Please verify again.' });
  }

  next();
}

app.get('/api/protected-resource', requireMFA, (req, res) => {
  res.json({
    success: true,
    message: 'Access granted to protected resource',
    userId: req.session.userId
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;